  display: flex;
  align-items: center;
  justify-content: space-between;
+ flex-wrap: nowrap; // Identity items must never wrap — see AP-066
  max-width: $elan-container-wide;
  margin: 0 auto;
  padding: var(--portfolio-spacer-1-5x) var(--portfolio-spacer-2x);

  @media #{$elan-mq-sm} {
    padding: var(--portfolio-spacer-1-5x) var(--portfolio-spacer-4x);
  }
}

.logo {
  display: inline-flex;
  align-items: center;
  gap: $portfolio-spacer-0-5x;
  text-decoration: none;
  // The logo is the site's core identity line. It must NEVER wrap or shrink
  // under flex pressure, at any viewport width. This is a design principle,
  // not a preference: core identity lines (logo, name) are rigid. The tagline
  // beside it is the soft edge that yields by wrapping. See AP-066.
  flex-shrink: 0;
+ white-space: nowrap; // Prevents logoMark + logoText from stacking — AP-066
  @include transition-fast;

  &:hover {
    .logoMark {
      background-color: var(--portfolio-text-neutral-max);
    }
    .logoText {
      color: var(--portfolio-text-neutral-max);
    }
  }
}

// .logoMark — no change needed (flex-shrink: 0 already present)

// .logoText — white-space: nowrap remains as belt-and-suspenders
// (it's the right guard on the text node too; the container guard is the
// load-bearing one, this is just defense-in-depth)

.links {
  display: flex;
  align-items: center;
  gap: var(--portfolio-spacer-3x);
  // The soft edge of the nav. Yields to narrow viewports by allowing
  // the tagline child to wrap. min-width: 0 lets this shrink past its
  // intrinsic content size so the logo NEVER has to give up space. AP-066.
  min-width: 0;
+ flex-shrink: 1; // Explicit: this side yields so the logo never has to
}
```

